var ROADMAP = [
  {level:'A1', title:'A1 — Alapok', sub:'Az angol alapjai', color:'cefr-a1', items:[

    {id:'a1_to_be', en:'To be', title:'To be (am/is/are)', sub:'I am, she is, they are',
     use:'Személyek, dolgok leírásához: azonosítás, tulajdonság, foglalkozás, helyszín kifejezése.',
     form:['(+) I am, you are, he/she/it is, we/you/they are','(-) I am not (I\'m not), she is not (isn\'t), they are not (aren\'t)','(?) Am I? Is she? Are they?'],
     signals:['Foglalkozások: I am a manager.','Tulajdonságok: She is busy.','Helyszín: We are in the office.'],
     examples:[{en:'I\'m a project manager at an IT company.',hu:'IT cégnél vagyok projektmenedzser.'},{en:'The meeting isn\'t cancelled.',hu:'A megbeszélés nincs lemondva.'},{en:'Are you the new team leader?',hu:'Te vagy az új csapatvezető?'}],
     warning:'NEM használunk segédigét: "He is work here" HELYTELEN. "He works here" — a to be önmagában is teljes ige.',
     contrast:null},

    {id:'a1_present_simple', en:'Present Simple', title:'Present Simple', sub:'I work, she works',
     use:'Szokások, rendszeres cselekvések; általános igazságok, tények; állandó helyzetek kifejezésére.',
     form:['(+) I/you/we/they + V1 alapalak | he/she/it + V1 + -s/-es','(-) I/you/we/they don\'t + V1 | he/she/it doesn\'t + V1','(?) Do I/you/we/they + V1? | Does he/she/it + V1?'],
     signals:['always, usually, often, sometimes, never','every day/week/month','on Mondays, at 9am'],
     examples:[{en:'She sends weekly reports to all stakeholders.',hu:'Hetente küld jelentést az összes érdekeltnek.'},{en:'The system doesn\'t support legacy software.',hu:'A rendszer nem támogatja az örökölt szoftvereket.'},{en:'Does the CEO approve all contracts?',hu:'Az ügyvezető hagy jóvá minden szerződést?'}],
     warning:'"He work here" — HELYTELEN. He/she/it esetén kötelező a -s/-es: "He works here."',
     contrast:'Present Simple vs Present Continuous: szokás (PS) vs éppen zajló cselekvés (PC). "I work from home" (általában) vs "I\'m working from home this week" (most, ideiglenesen).'},

    {id:'a1_present_continuous', en:'Present Continuous', title:'Present Continuous', sub:'I am working, she is presenting',
     use:'Éppen most zajló cselekvések; ideiglenes helyzetek; közeli jövőre vonatkozó konkrét tervek.',
     form:['(+) am/is/are + V-ing','(-) am/is/are + not + V-ing','(?) Am/Is/Are + alany + V-ing?'],
     signals:['now, right now, at the moment','currently, at present','this week/month (ideiglenes)','tonight, tomorrow (konkrét terv)'],
     examples:[{en:'We\'re currently reviewing the contract.',hu:'Jelenleg átnézzük a szerződést.'},{en:'She isn\'t attending the conference this year.',hu:'Idén nem vesz részt a konferencián.'},{en:'Are you presenting tomorrow?',hu:'Te prezentálsz holnap?'}],
     warning:'"I am knowing" — HELYTELEN. Állapotot kifejező igékkel (know, believe, want, like, need, own) NEM használjuk a Continuous alakot.',
     contrast:'Present Simple vs Present Continuous: "I work in London" (általában ott dolgozom) vs "I\'m working in London" (most ideiglenesen ott vagyok).'},

    {id:'a1_articles', en:'Articles: a / an / the', title:'Articles: a / an / the', sub:'a report, an email, the meeting',
     use:'"a/an" = először említett, nem konkrét dolog. "the" = már ismert, konkrét, egyedi dolog. Névelő nélkül: általános fogalmak, tulajdonnevek, anyagnevek.',
     form:['"a" + mássalhangzóval kezdődő szó: a report, a team, a user','"an" + magánhangzóval kezdődő szó (a,e,i,o,u): an email, an hour, an update','"the" = konkrét, azonosítható, már említett dolog','Nincs névelő: általános (I like coffee), tulajdonnevek (London), többes általános (Meetings are useful)'],
     signals:['"a/an": first mention, any one of many','"the": second mention, only one, superlatives, shared knowledge'],
     examples:[{en:'I received an email from a client.',hu:'Kaptam egy e-mailt egy ügyféltől.'},{en:'The email was about the new contract.',hu:'Az e-mail az új szerződésről szólt.'},{en:'She\'s the CEO of the company.',hu:'Ő a cég ügyvezetője.'}],
     warning:'"I have meeting at 3" — HELYTELEN. Számolható főnév előtt mindig kell névelő: "I have a meeting at 3."',
     contrast:null},

    {id:'a1_there_is', en:'There is / There are', title:'There is / There are', sub:'There is a problem, There are issues',
     use:'Dolgok létezésének, jelenlétének kifejezése. Nincs magyarban közvetlen megfelelője az igei szerkezetnek — egyszerűen "van/vannak".',
     form:['There is + egyes számú főnév','There are + többes számú főnév','(-) There isn\'t / There aren\'t','(?) Is there? / Are there?'],
     signals:['Új információ bevezetésekor','Helyszínek leírásakor','Lehetőségek felsorolásakor'],
     examples:[{en:'There\'s a conflict in the schedule.',hu:'Ütközés van a menetrendben.'},{en:'There are three options on the table.',hu:'Három lehetőség van az asztalon.'},{en:'Is there a backup plan?',hu:'Van tartalékterv?'}],
     warning:'"There is many options" — HELYTELEN. Többes szám → There are: "There are many options."',
     contrast:null},

    {id:'a1_imperatives', en:'Imperatives', title:'Imperatives', sub:'Send the report. Don\'t forget.',
     use:'Utasítások, kérések, javaslatok, instrukciók adásához — írott és szóbeli kommunikációban egyaránt.',
     form:['(+) V1 alapalak: Send, Click, Check, Call','(-) Don\'t + V1: Don\'t share, Don\'t forget','Udvariasabb: Please + V1 | Could you + V1?'],
     signals:['Írásbeli instrukciókban','E-mail zárásokban: Please find attached...','Prezentációban: See the chart below.'],
     examples:[{en:'Please send me the updated version by Friday.',hu:'Kérem küldje el a frissített verziót péntekig.'},{en:'Don\'t share this document outside the team.',hu:'Ne ossza meg ezt a dokumentumot a csapaton kívül.'},{en:'Click here to confirm your attendance.',hu:'Kattintson ide a részvétel megerősítéséhez.'}],
     warning:'"Please to send" — HELYTELEN. Please után V1 alapalak kell, to nélkül: "Please send."',
     contrast:null}
  ]},

  {level:'A2', title:'A2 — Alapszint', sub:'Múlt idő, alapvető struktúrák', color:'cefr-a2', items:[

    {id:'a2_past_simple', en:'Past Simple', title:'Past Simple', sub:'I worked, she went, we signed',
     use:'Lezárult, konkrét múltbeli cselekvések és események kifejezésére — különösen ha az időpont ismert vagy meghatározott.',
     form:['(+) Szabályos: V1 + -ed | Szabálytalan: egyedi alak (went, sent, made, wrote)','(-) didn\'t + V1 alapalak','(?) Did + alany + V1 alapalak?'],
     signals:['yesterday, last week/month/year','in 2020, on Monday, at 3pm','ago: two days ago','when: When I arrived...'],
     examples:[{en:'We signed the contract last Thursday.',hu:'Múlt csütörtökön aláírtuk a szerződést.'},{en:'The client didn\'t approve the proposal.',hu:'Az ügyfél nem hagyta jóvá a javaslatot.'},{en:'Did you send the invoice this morning?',hu:'Elküldted a számlát ma reggel?'}],
     warning:'"I did sent" — HELYTELEN. Did után V1 alapalak kell: "I sent" vagy "Did you send?"',
     contrast:'Past Simple vs Present Perfect: konkrét múlt időpont = PS ("I sent it yesterday"). Nincs konkrét időpont, csak eredmény = PP ("I have sent it").'},

    {id:'a2_past_continuous', en:'Past Continuous', title:'Past Continuous', sub:'I was working, she was presenting',
     use:'Múltbeli folyamat közben megszakított cselekvés; két párhuzamos múltbeli cselekvés; háttér-cselekvés elbeszélésben.',
     form:['(+) was/were + V-ing','(-) wasn\'t/weren\'t + V-ing','(?) Was/Were + alany + V-ing?'],
     signals:['when (a főesemény megszakítja): ...when the phone rang','while (párhuzamos): While I was presenting, she was taking notes','at 3pm yesterday (folyamat egy pillanatban)'],
     examples:[{en:'I was reviewing the report when the client called.',hu:'Épp a jelentést néztem át, amikor az ügyfél hívott.'},{en:'While the team was preparing, the manager was briefing the board.',hu:'Amíg a csapat készülődött, a menedzser tájékoztatta az igazgatóságot.'},{en:'What were you working on yesterday afternoon?',hu:'Min dolgoztál tegnap délután?'}],
     warning:'"She was work on it" — HELYTELEN. Past Continuous: was/were + V-ING: "She was working on it."',
     contrast:'Past Simple vs Past Continuous: PS = lezárult esemény ("she called"), PC = folyamat ("I was working") — általában együtt jelennek meg.'},

    {id:'a2_future_will', en:'Future: will', title:'Future with will', sub:'I\'ll send it. She won\'t attend.',
     use:'Spontán, az adott pillanatban meghozott döntések; ígéretek; jövőbeli előrejelzések, várakozások.',
     form:['(+) will + V1 (rövidítve: \'ll)','(-) will not + V1 (rövidítve: won\'t)','(?) Will + alany + V1?'],
     signals:['Spontán döntésnél: "I\'ll do it now."','Ígéreteknél: I promise I\'ll...','Előrejelzésnél: I think, probably, I\'m sure'],
     examples:[{en:'I\'ll send you the updated figures right away.',hu:'Rögtön elküldöm a frissített adatokat.'},{en:'The project won\'t be ready by Friday at this rate.',hu:'Ilyen ütemben nem lesz kész a projekt péntekre.'},{en:'Will you be available for a call this afternoon?',hu:'Elérhető leszel egy hívásra ma délután?'}],
     warning:'"I will to send" — HELYTELEN. Will után V1 alapalak kell, to nélkül: "I will send."',
     contrast:'"will" vs "going to": spontán döntés = will ("I\'ll call him"). Előre eltervezett szándék = going to ("I\'m going to call him — it\'s in my calendar").'},

    {id:'a2_future_going_to', en:'Future: going to', title:'Future with going to', sub:'We\'re going to launch. She\'s not going to renew.',
     use:'Előre eltervezett szándékok és döntések; látható jelekből következő előrejelzések.',
     form:['(+) am/is/are + going to + V1','(-) am/is/are + not + going to + V1','(?) Am/Is/Are + alany + going to + V1?'],
     signals:['Szándék: I\'ve decided, I\'ve planned, we\'ve arranged','Előrejelzés bizonyíték alapján: Look at..., The figures show...'],
     examples:[{en:'We\'re going to restructure the sales team next quarter.',hu:'Jövő negyedévben átszervezzük az értékesítési csapatot.'},{en:'She\'s not going to renew her contract — she told me yesterday.',hu:'Nem fogja megújítani a szerződését — tegnap mondta el nekem.'},{en:'Look at these numbers — we\'re going to miss the target.',hu:'Nézzük ezeket a számokat — el fogjuk szalasztani a célt.'}],
     warning:'"We are go to launch" — HELYTELEN. Going to után V1 alapalak kell: "We are going to launch."',
     contrast:'"going to" vs "will": előre tervezett = going to. Spontán = will. Mindkettő helyes előrejelzésnél, de going to erősebb bizonyíték esetén.'},

    {id:'a2_modal_can', en:'Modal: can / could', title:'can / could', sub:'I can help. Could you review this?',
     use:'"can" = képesség, lehetőség, engedélykérés (informális). "could" = múltbeli képesség; udvariasabb kérés; lehetőség.',
     form:['can/could + V1 alapalak (SOHA nem to + ige)','(-) cannot (can\'t) / couldn\'t','(?) Can/Could + alany + V1?'],
     signals:['"can": ability ("I can speak French"), permission ("Can I leave early?")','\"could\": polite request ("Could you send me...?"), past ability ("I could run fast when I was young")'],
     examples:[{en:'I can handle the presentation if you need backup.',hu:'El tudom végezni a prezentációt, ha kell a segítség.'},{en:'Could you review this proposal before the meeting?',hu:'Tudná átnézni ezt a javaslatot a megbeszélés előtt?'},{en:'We couldn\'t reach an agreement in the first round.',hu:'Nem tudtunk megállapodásra jutni az első körben.'}],
     warning:'"I can to speak" — HELYTELEN. Modal igék után NINCS to: "I can speak."',
     contrast:'"Can you help?" (informális, közvetlen) vs "Could you help?" (udvariasabb, formálisabb) — üzleti kontextusban could az ajánlott.'},

    {id:'a2_modal_must_should', en:'must / should / have to', title:'must / should / have to', sub:'You must submit. You should prepare.',
     use:'"must" = erős belső kötelezettség, meggyőződés. "have to" = külső szabály, elvárás. "should" = tanács, ajánlás, elvárás.',
     form:['must/should + V1 (NINCS to)','have to: have/has to + V1','(-) mustn\'t = TILOS | don\'t have to = NEM KÖTELEZŐ (de szabad)','(-) shouldn\'t = nem ajánlott'],
     signals:['"must": belső meggyőződés, erős ajánlás','\"have to\": külső szabály, körülmény kényszeríti','\"should\": tanács, elvárás, javaslat'],
     examples:[{en:'All invoices must be approved before payment.',hu:'Minden számlát jóvá kell hagyni fizetés előtt.'},{en:'You should include a risk assessment in the report.',hu:'Érdemes kockázatértékelést is bevenni a jelentésbe.'},{en:'You don\'t have to attend — it\'s optional.',hu:'Nem kell eljönnöd — opcionális.'}],
     warning:'"Mustn\'t" ≠ "don\'t have to". Mustn\'t = TILOS cselekedni. Don\'t have to = nem kötelező, de megteheted.',
     contrast:'"must" vs "have to": erős saját meggyőződés = must. Külső szabály/körülmény = have to. Formális írásban mindkettő elfogadott.'},

    {id:'a2_comparatives', en:'Comparatives & Superlatives', title:'Comparatives & Superlatives', sub:'better, more efficient, the best',
     use:'Két dolog összehasonlítása (comparative); vagy egy dolog kiemelése egy csoportból (superlative).',
     form:['Rövid melléknév (1-2 szótag): -er / the -est: fast → faster → the fastest','Hosszú melléknév (2+ szótag): more/less / the most/least: efficient → more efficient → the most efficient','Szabálytalan: good→better→best | bad→worse→worst | far→further→furthest'],
     signals:['Comparative: than ("faster than"), compared to','Superlative: the + ...-est / the most..., in (the team), of (all options)'],
     examples:[{en:'This solution is more cost-effective than the current one.',hu:'Ez a megoldás gazdaságosabb a jelenlegi megoldásnál.'},{en:'Q3 was our worst quarter in three years.',hu:'A harmadik negyedév volt a legjobb negyedévünk három évben.'},{en:'She\'s the most experienced candidate we\'ve interviewed.',hu:'Ő a legtapasztaltabb jelölt, akivel interjúztunk.'}],
     warning:'"More better" / "more faster" — HELYTELEN. Rövid mellékneveknél CSAK -er: "better", "faster" (nem "more better").'},

    {id:'a2_present_perfect_intro', en:'Present Perfect (intro)', title:'Present Perfect — bevezetés', sub:'I have sent it. She has finished.',
     use:'Múltbeli cselekvések, amelyeknek relevanciája van a jelenben; tapasztalatok (konkrét időpont nélkül); most elvégzett cselekvések.',
     form:['(+) have/has + past participle (3. igealak)','(-) haven\'t/hasn\'t + past participle','(?) Have/Has + alany + past participle?'],
     signals:['just (épp most): I\'ve just sent it.','already (már): She\'s already finished.','yet (még nem / már): Have you finished yet? / I haven\'t finished yet.','ever/never: Have you ever presented to a board?'],
     examples:[{en:'I\'ve just sent the revised proposal to the client.',hu:'Épp most küldtem el a felülvizsgált javaslatot az ügyfélnek.'},{en:'She hasn\'t responded to our email yet.',hu:'Még nem válaszolt az e-mailünkre.'},{en:'Have you ever worked on an international project?',hu:'Dolgoztál már nemzetközi projekten?'}],
     warning:'"I have seen him yesterday" — HELYTELEN. Konkrét múlt időpont (yesterday) → Past Simple: "I saw him yesterday."',
     contrast:'Present Perfect vs Past Simple: PP = nincs konkrét időpont, fontos az eredmény. PS = konkrét múlt időpont meghatározott.'}
  ]},

  {level:'B1', title:'B1 — Középhaladó', sub:'Igeidők rendszere, kondicionális', color:'cefr-b1', items:[

    {id:'b1_present_perfect', en:'Present Perfect', title:'Present Perfect — mélyítés', sub:'I\'ve worked here for 5 years.',
     use:'Múlttól a jelenig tartó, folyamatos helyzetek (for/since); eredmény fontosabb mint a múlt időpont; változások, fejlemények.',
     form:['(+) have/has + past participle','(-) haven\'t/hasn\'t + past participle','(?) Have/Has + alany + past participle?','PP Continuous: have/has + been + V-ing (folyamatra hangsúly)'],
     signals:['for + időtartam: for three years, for a month','since + időpont: since 2020, since Monday','recently, lately, so far, up to now','How long...?'],
     examples:[{en:'I\'ve worked in IT security for over five years.',hu:'Több mint öt éve dolgozom IT biztonságban.'},{en:'We\'ve been negotiating with this client since January.',hu:'Januártól tárgyalunk ezzel az ügyféllel.'},{en:'The market has changed significantly recently.',hu:'A piac jelentősen változott az utóbbi időben.'}],
     warning:'"I have worked here since five years" — HELYTELEN. Időtartam = for. Időpont = since: "for five years" / "since 2019".',
     contrast:'PP vs Past Simple: "I worked there" (és ez lezárult). "I\'ve worked there" (és ez kapcsolódik a jelenhez, vagy még most is ott dolgozom).'},

    {id:'b1_past_perfect', en:'Past Perfect', title:'Past Perfect', sub:'She had left before I arrived.',
     use:'Egy múltbeli esemény előtt megtörtént másik esemény kifejezésére — az időbeli sorrend egyértelműsítéséhez.',
     form:['(+) had + past participle','(-) hadn\'t + past participle','(?) Had + alany + past participle?'],
     signals:['by the time: By the time I arrived, she had left.','before, after, when (sorrendet kiemelve)','already: He had already left.','just: She had just finished.'],
     examples:[{en:'By the time the client arrived, we had already prepared the presentation.',hu:'Mire az ügyfél megérkezett, már elkészítettük a prezentációt.'},{en:'She hadn\'t seen the report when we discussed it.',hu:'Még nem látta a jelentést, amikor megbeszéltük.'},{en:'Had you worked with them before this project?',hu:'Dolgoztál velük már ezen a projekten kívül?'}],
     warning:'"By the time she arrived, we finished" — HELYTELEN. A korábban befejezett esemény → Past Perfect: "we had finished".',
     contrast:'Past Perfect vs Past Simple: mindkettő múlt, de PP a korábbi esemény. "She left. Then I arrived." → "She had left when I arrived."'},

    {id:'b1_passive_voice', en:'Passive Voice', title:'Passive Voice', sub:'The contract was signed. The report is reviewed.',
     use:'A cselekvés elszenvedője a fontos, nem a cselekvő; a cselekvő ismeretlen vagy nyilvánvaló; formális, tárgyilagos hang — üzleti szövegekben.',
     form:['Jelen: am/is/are + past participle','Múlt: was/were + past participle','Jövő: will be + past participle','Modal: must be / should be / can be + past participle','by + cselekvő (ha fontos megnevezni)'],
     signals:['Üzleti írásban: "The budget was approved..."','Folyamatleírásoknál: "The data is collected, then analysed..."','Cselekvő ismeretlen: "The file was deleted."'],
     examples:[{en:'The contract was reviewed by the legal team before signing.',hu:'A szerződést az aláírás előtt a jogi csapat vizsgálta felül.'},{en:'All expenses must be submitted by the end of the month.',hu:'Minden kiadást be kell nyújtani a hónap végéig.'},{en:'A decision will be made after the board meeting.',hu:'Döntés az igazgatósági ülés után fog születni.'}],
     warning:'"The report was wrote by the team" — HELYTELEN. Write szabálytalan: write → wrote → written: "was written".',
     contrast:'Active vs Passive: "The manager approved the budget" (ki cselekedett a fontos) vs "The budget was approved" (mi történt a fontos, nem ki csinálta).'},

    {id:'b1_conditionals_1_2', en:'Conditionals 1 & 2', title:'First & Second Conditional', sub:'If we win, we\'ll... / If I were you...',
     use:'1st: valós, lehetséges jövőbeli feltétel és következménye. 2nd: képzeletbeli, valószínűtlen vagy hipotetikus helyzet.',
     form:['1st: If + Present Simple, will + V1','2nd: If + Past Simple, would + V1','2nd: "If I were" (NEM "If I was" — formális)','Felcserélhető: Would you...if...? / If..., would...?'],
     signals:['1st: valós lehetőség ("If we reduce costs...")','2nd: hipotetikus ("If I were the CEO...", "If I had more time...")','would like to, could, might (2nd-ben)'],
     examples:[{en:'If we reduce the budget by 10%, we\'ll meet the quarterly target.',hu:'Ha 10%-kal csökkentjük a költségvetést, teljesítjük a negyedéves célt.'},{en:'If I were in your position, I\'d negotiate a longer deadline.',hu:'Ha a te helyzetedben lennék, hosszabb határidőt tárgyalnék ki.'},{en:'Would you accept the offer if they increased the salary?',hu:'Elfogadnád az ajánlatot, ha emelnék a fizetést?'}],
     warning:'"If I would be..." — HELYTELEN. 2nd conditional: If + Past Simple (were): "If I were..." — a "would" csak a főmondatban van.',
     contrast:'1st vs 2nd: "If it rains, I\'ll cancel" (lehetséges, reális) vs "If it rained, I\'d cancel" (hipotetikus, valószínűtlen).'},

    {id:'b1_reported_speech', en:'Reported Speech', title:'Reported Speech', sub:'She said she would send it.',
     use:'Más személy szavainak, kérdéseinek, gondolatainak közvetítéséhez — meetingösszefoglalókban, e-mailekben különösen fontos.',
     form:['say (that) + mellékmondat | tell + személyes tárgy + (that) + mellékmondat','Igeidő visszalépés: is→was, will→would, can→could, have→had','Idő/hely váltás: now→then, here→there, today→that day','Kérdés: asked if/whether (igen/nem) | asked + kérdőszó'],
     signals:['said, told, mentioned, explained, confirmed, asked, suggested, promised'],
     examples:[{en:'She said the project would be delayed by two weeks.',hu:'Azt mondta, a projekt két héttel késni fog.'},{en:'He told me he hadn\'t received the invoice.',hu:'Azt mondta nekem, hogy nem kapta meg a számlát.'},{en:'They asked whether we could reduce the delivery time.',hu:'Megkérdezték, hogy le tudjuk-e rövidíteni a szállítási időt.'}],
     warning:'"He said me..." — HELYTELEN. Say után nincs személyes tárgy: "He said (that)...". Tell után VAN: "He told me (that)...".',
     contrast:'"say" vs "tell": say = nincs közvetlen tárgy ("She said it was fine"). tell = van közvetlen tárgy ("She told me it was fine").'},

    {id:'b1_modal_advanced', en:'Modal Verbs — Advanced', title:'Modal Verbs: Past Forms', sub:'must have, should have, can\'t have',
     use:'Múltbeli eseményekre vonatkozó következtetés, spekuláció, sajnálat, kritika kifejezése.',
     form:['must have + PP = biztosan megtörtént (következtetés)','can\'t have + PP = biztosan NEM történt','might/could have + PP = lehetséges, hogy megtörtént','should have + PP = kellett volna (sajnálat, kritika)','needn\'t have + PP = felesleges volt'],
     signals:['Következtetés bizonyíték alapján: must have','Erős kétség: can\'t have','Bizonytalanság: might have, could have','Sajnálat/kritika: should have, shouldn\'t have'],
     examples:[{en:'She must have missed the notification — she wasn\'t prepared.',hu:'Biztosan nem vette észre az értesítést — nem volt felkészülve.'},{en:'You should have informed the client earlier about the delay.',hu:'Korábban kellett volna tájékoztatni az ügyfelet a késésről.'},{en:'They can\'t have agreed to those terms — it\'s against their policy.',hu:'Biztosan nem egyeztek bele azokba a feltételekbe — ellentétes a politikájukkal.'}],
     warning:'"She must have not received it" — HELYTELEN. Tagadás: "She can\'t have received it" (biztosan nem) vagy "She might not have received it" (lehet, hogy nem).',
     contrast:'"must have" (99% biztos) vs "might have" (50% lehetséges) vs "can\'t have" (0% lehetséges).'},

    {id:'b1_future_continuous_perfect', en:'Future Continuous & Perfect', title:'Future Continuous & Perfect', sub:'will be working / will have finished',
     use:'Future Continuous: jövőbeli időpontban éppen zajló cselekvés. Future Perfect: jövőbeli időpontig befejezett cselekvés.',
     form:['Future Continuous: will be + V-ing','Future Perfect: will have + past participle','(-) won\'t be + V-ing | won\'t have + PP','(?) Will + alany + be + V-ing? | Will + alany + have + PP?'],
     signals:['Future Continuous: this time tomorrow/next week, at 3pm on Friday','Future Perfect: by + időpont (by Friday, by the end of the month)','before + esemény'],
     examples:[{en:'This time tomorrow I\'ll be presenting to the board.',hu:'Holnap ilyenkor épp az igazgatóságnak prezentálok majd.'},{en:'By the end of the week, we will have completed the audit.',hu:'A hét végéig befejezzük az auditot.'},{en:'Will you be using the conference room at 2pm?',hu:'Fogod te a tárgyalót használni 2-kor?'}],
     warning:'"By Friday I will finish" — HELYTELEN, ha azt akarod mondani, hogy befejezed a pénteki határidő ELŐTT. Ilyenkor: "I will have finished by Friday."',
     contrast:'Future Continuous = folyamat egy jövőbeli pillanatban. Future Perfect = befejezettség egy jövőbeli határidőig.'},

    {id:'b1_relative_clauses', en:'Relative Clauses', title:'Relative Clauses', sub:'the client who called / the report which...',
     use:'Főnév pontosabb azonosítása (defining) vagy kiegészítő információ hozzáadása (non-defining).',
     form:['who = személyekre','which = dolgokra, állatokra','that = személyekre és dolgokra (CSAK defining)','whose = birtok kifejezése','where = helyre','Non-defining: vesszővel elválasztva, SOHA nem "that"'],
     signals:['Defining (nincs vessző): "The manager who called yesterday..."','Non-defining (vesszővel): "Our CEO, who joined last year, ..."','whose = "The company whose shares..."'],
     examples:[{en:'The client who called yesterday wants to renegotiate the terms.',hu:'Az ügyfél, aki tegnap hívott, újra akarja tárgyalni a feltételeket.'},{en:'The report, which was submitted last week, contains an error.',hu:'A múlt héten benyújtott jelentés hibát tartalmaz.'},{en:'We\'re working with a company whose CEO I met at the conference.',hu:'Egy olyan céggel dolgozunk, amelynek az ügyvezetőjével a konferencián találkoztam.'}],
     warning:'"The person which called" — HELYTELEN. Személyre: who (nem which): "The person who called."',
     contrast:'Defining vs Non-defining: "The employee who was promoted left." (melyik alkalmazott — azonosít) vs "John, who was promoted, left." (extra info, vesszővel).'},

    {id:'b1_gerund_infinitive', en:'Gerund & Infinitive', title:'Gerund & Infinitive', sub:'I enjoy presenting / I want to present',
     use:'Bizonyos igék után gerund (-ing) áll, mások után to + infinitive. A különbség néha jelentésváltozással jár.',
     form:['Gerund (-ing) után: enjoy, avoid, suggest, recommend, consider, finish, mind, keep','To + infinitive után: want, need, decide, plan, expect, manage, refuse, hope, offer','Mindkettő, AZONOS jelentéssel: like, love, hate, prefer, start, begin, continue','Mindkettő, ELTÉRŐ jelentéssel: remember, stop, try, forget, regret'],
     signals:['Gerund: cselekvés mint fogalom / szokás','To + inf: konkrét szándék, jövőbeli cselekvés'],
     examples:[{en:'I suggest reviewing the contract with the legal team.',hu:'Javaslom, hogy a jogi csapattal nézzük át a szerződést.'},{en:'We\'ve decided to postpone the product launch.',hu:'Úgy döntöttünk, elhalasztjuk a termék bevezetését.'},{en:'Remember to send the agenda before the meeting.',hu:'Ne felejts el napirendi pontot küldeni a megbeszélés előtt.'}],
     warning:'"I suggest to review" — HELYTELEN. Suggest után gerund: "I suggest reviewing."',
     contrast:'"remember + -ing" = emlékszem, hogy (megtettem): "I remember sending it." | "remember + to" = ne felejtsük el (megtenni): "Remember to send it."'},

    {id:'b1_connectors', en:'Connectors & Cohesion', title:'Discourse Connectors', sub:'however, although, therefore, despite',
     use:'Mondatok és bekezdések logikai összekapcsolásához — kontrast, ok-okozat, engedmény, kiegészítés kifejezéséhez.',
     form:['Kontrast: however, nevertheless, on the other hand, whereas, while','Ok/okozat: therefore, as a result, consequently, hence','Engedmény: although, even though, despite + noun/-ing, in spite of','Kiegészítés: furthermore, in addition, moreover, what\'s more','Összefoglalás: in conclusion, to sum up, overall'],
     signals:['Új gondolat hozzáadásakor: furthermore','Ellentétes gondolatnál: however, on the other hand','Ok/eredmény: therefore, as a result','Meglepő/váratlan eredmény: nevertheless'],
     examples:[{en:'The project was delivered late; however, the quality exceeded expectations.',hu:'A projekt késve érkezett; mindazonáltal a minőség felülmúlta az elvárásokat.'},{en:'Despite the budget cuts, the team achieved record results.',hu:'A költségcsökkentések ellenére a csapat rekorderedményeket ért el.'},{en:'Sales increased by 20%; as a result, we\'re hiring five new team members.',hu:'Az értékesítés 20%-kal nőtt; ennek eredményeként öt új csapattagot veszünk fel.'}],
     warning:'"Although the costs increased, but the quality improved" — HELYTELEN. Although és but NEM kerülhet ugyanabba a mondatba.',
     contrast:'"although/even though" + teljes mellékmondat vs "despite/in spite of" + főnév vagy -ing: "Although it was late..." vs "Despite being late..."'}
  ]},

  {level:'B2', title:'B2 — Haladó', sub:'Összetett szerkezetek, árnyalás', color:'cefr-b2', items:[

    {id:'b2_narrative_tenses', en:'Narrative Tenses', title:'Narrative Tenses', sub:'was working, had finished, used to',
     use:'Összetett múltbeli elbeszéléshez: háttér, főesemény, korábbi előzmény és múltbeli szokások kombinálása.',
     form:['Past Simple: főesemény (lezárult, sorrendben)','Past Continuous: háttér, párhuzamos cselekvés','Past Perfect: a főeseményt megelőző esemény','used to / would: múltbeli szokások, rendszeres cselekvések'],
     signals:['PS: sorrendben lezárult: "she called, I answered"','PC: when...was -ing (háttér)','PP: by the time, before, already','used to: általános múltbeli szokás (állapot is)','would: ismétlődő múltbeli cselekvés (NEM állapot)'],
     examples:[{en:'When I joined the company, the team had already been working on the project for six months.',hu:'Amikor beléptem a cégbe, a csapat már hat hónapja dolgozott a projekten.'},{en:'She used to travel every week, but now she works entirely remotely.',hu:'Korábban minden héten utazott, de most teljesen távolról dolgozik.'},{en:'I was reviewing the Q3 figures when the CEO called.',hu:'A Q3-as számokat néztem át, amikor az ügyvezető hívott.'}],
     warning:'"I would live in London" (állapot = HELYTELEN múltbeli szokásként). Állapotoknál used to: "I used to live in London."',
     contrast:'"used to" = múltbeli szokás/állapot (ma már nem igaz). "would" = ismétlődő múltbeli cselekvés (nem állapotra).'},

    {id:'b2_passive_advanced', en:'Passive Voice — Advanced', title:'Advanced Passive Structures', sub:'It is believed... / He is said to be...',
     use:'Személytelen passzív: tények, vélemények tárgyilagos közlésére. Causative have/get: mással elvégeztetett cselekvés.',
     form:['Személytelen: It is said/believed/reported/known that + clause','Személyes: He is said to be... / She is believed to have...','Causative: have/get + tárgy + past participle','Passzív infinitive: need to be done, should be checked'],
     signals:['Objektív hangnem: "It has been confirmed that..."','Hírek, jelentések: "It is reported that..."','Causative: "We had the system audited" (mással csináltatjuk)'],
     examples:[{en:'It is widely believed that remote work increases productivity.',hu:'Széles körben hiszik, hogy a távmunka növeli a termelékenységet.'},{en:'The CEO is said to be considering a merger.',hu:'Az ügyvezetőről azt mondják, hogy összeolvadást fontolgat.'},{en:'We had the entire codebase reviewed by an external security firm.',hu:'Egy külső biztonsági céggel néztettük át a teljes kódbázist.'}],
     warning:'"The CEO is said to being..." — HELYTELEN. Passive reporting: is said to be (infinitive, nem -ing).',
     contrast:'"It is said that he is wealthy" = személytelen. "He is said to be wealthy" = személyes passzív — mindkettő helyes, a személyes változat formálisabb.'},

    {id:'b2_conditionals_3', en:'Third & Mixed Conditionals', title:'Third & Mixed Conditionals', sub:'If I had known... / If she had taken the job...',
     use:'3rd: múltbeli feltétel, ami nem valósult meg — és következménye. Mixed: múltbeli ok + jelenbeli/jövőbeli következmény.',
     form:['3rd: If + Past Perfect, would have + past participle','Mixed (múlt→jelen): If + Past Perfect, would + V1','Mixed (jelen→múlt): If + Past Simple, would have + PP','Inverted (formális): Had + alany + PP, ... (if elhagyható)'],
     signals:['3rd: múltbeli döntések, hibák, lehetőségek','Mixed: múltbeli oknak jelenbeli hatása van','Inverted: Had I known... (formális írásban)'],
     examples:[{en:'If we had invested in that technology, we would have dominated the market by now.',hu:'Ha abba a technológiába fektettünk volna, mára uraltuk volna a piacot.'},{en:'If she had taken the role in Singapore, she would be leading the APAC region now.',hu:'Ha elvállalta volna a szingapúri pozíciót, most az APAC régiót vezette volna.'},{en:'Had you informed us earlier, we could have found an alternative supplier.',hu:'Ha korábban tájékoztattatok volna minket, találhattunk volna alternatív szállítót.'}],
     warning:'"If I would have known..." — HELYTELEN. 3rd conditional: If + Past Perfect (had known), NEM would have.',
     contrast:'3rd = teljes múlt: múlt feltétel → múlt következmény. Mixed = vegyes: múlt feltétel → jelen/jövő következmény.'},

    {id:'b2_wish_regret', en:'Wish / If only', title:'wish / if only', sub:'I wish I had more time. If only we\'d known.',
     use:'Valóságtól eltérő kívánságok, sajnálat múltbeli dolgok miatt, bosszankodás mások viselkedése miatt.',
     form:['Jelenbeli kívánság: wish + Past Simple ("I wish I had more time")','Múltbeli sajnálat: wish + Past Perfect ("I wish I had told him")','Bosszankodás: wish + would + V1 ("I wish he would stop interrupting")','If only = erőteljesebb változat (érzelmileg hangsúlyosabb)'],
     signals:['Jelenbeli kívánság: valóság vs kívánság (de nem igaz)','Múltbeli sajnálat: bárcsak másképpen döntöttem volna','Bosszankodás: valaki (más) viselkedésével elégedetlenség'],
     examples:[{en:'I wish we had more time to prepare for the pitch.',hu:'Bárcsak több időnk lenne felkészülni a pitchre.'},{en:'If only we\'d secured the contract before the price increase.',hu:'Ha csak a drágulás előtt biztosítottuk volna a szerződést.'},{en:'I wish the client would respond more promptly to our emails.',hu:'Bárcsak az ügyfél gyorsabban válaszolna az e-mailjeinkre.'}],
     warning:'"I wish I would have more time" — HELYTELEN. Jelenbeli kívánság: wish + Past Simple: "I wish I had more time."',
     contrast:'"I wish" = személyes, belső hang. "If only" = erőteljesebb, dramatikusabb, érzelmileg hangsúlyosabb.'},

    {id:'b2_inversion', en:'Inversion', title:'Inversion for Emphasis', sub:'Never have I... / Not only did we...',
     use:'Hangsúly és drámai hatás — főleg formális szövegekben, prezentációk nyitásában/zárásában, üzleti jelentésekben.',
     form:['Negatív határozó + segédige + alany + főige','Never/Rarely/Seldom + have/did/will + alany + V1','Not only... but also (inverzió az első tagban)','Under no circumstances + will/would + alany','Hardly/Scarcely + had + alany + PP... when/before'],
     signals:['Formális írott szöveg','Prezentáció, speech','Hangsúly negatív/korlátozó határozókon'],
     examples:[{en:'Never have I seen such a compelling business case presented to the board.',hu:'Soha nem láttam ilyen meggyőző üzleti esetet bemutatni az igazgatóságnak.'},{en:'Not only did we exceed the annual target, but we also reduced operating costs by 15%.',hu:'Nem csak az éves célt haladtuk meg, de az operatív költségeket is 15%-kal csökkentettük.'},{en:'Under no circumstances should this information be shared outside the organisation.',hu:'Ezt az információt semmi körülmények között nem szabad a szervezeten kívül megosztani.'}],
     warning:'"Rarely I have seen..." — HELYTELEN. Inverzió szükséges: "Rarely have I seen..."',
     contrast:'Normál szórend vs inverzió: "I have never seen this." (semleges) vs "Never have I seen this." (hangsúlyos, formális).'},

    {id:'b2_future_advanced', en:'Future Forms — Advanced', title:'Advanced Future Expressions', sub:'about to, due to, set to, on the verge of',
     use:'Pontosabb jövőbeli valószínűség, időbeliség és kontextus kifejezése — üzleti hírek, sajtóközlemények, elemzések nyelvén.',
     form:['be about to + V1 = azonnal bekövetkező','be due to + V1 = menetrend szerinti, várható','be set to + V1 = várható (különösen sajtóban)','be on the verge of + -ing = küszöbön álló (drámai)','be expected to + V1 = elvárás alapján várható'],
     signals:['"about to": azonnali jövő, figyelmeztetés','\"due to\": ütemterv, menetrend szerinti','\"set to\": sajtó, előrejelzés','\"on the verge of\": dramaturgia, fordulópont'],
     examples:[{en:'The company is about to announce a major restructuring.',hu:'A cég hamarosan bejelent egy nagy átszervezést.'},{en:'The new regulation is due to come into effect on 1 January.',hu:'Az új szabályozás január 1-jén lép hatályba.'},{en:'The market is set to grow by 18% over the next three years.',hu:'A piac várhatóan 18%-kal fog növekedni a következő három évben.'}],
     warning:'"The CEO is about to announcing" — HELYTELEN. Be about to + V1 alapalak (nem -ing): "is about to announce".',
     contrast:'"due to" = konkrét időpont/ütemterv. "about to" = nagyon hamarosan. "set to" = általánosabb előrejelzés.'},

    {id:'b2_relative_advanced', en:'Relative Clauses — Advanced', title:'Advanced Relative Clauses', sub:'which is why / the team with whom',
     use:'Haladó vonatkozó szerkezetek formális, precíz írott kommunikációhoz.',
     form:['Redukált relatív: that was → (elhagyható): "the report submitted" = "the report that was submitted"','Mondatvonatkoztatás: which (egész mondatra): "She was late, which surprised everyone."','Prepozíció + which/whom: "the team with which I worked" / "the client for whom we did this"','Whoever/whatever/wherever: általánosítás'],
     signals:['Redukált: rövidebb, formálisabb','Mondatvonatkoztatás: which = and this / which is why','Prepozíció: formális írásban'],
     examples:[{en:'The proposal submitted by the external team received the highest score.',hu:'A külső csapat által benyújtott javaslat kapta a legmagasabb pontszámot.'},{en:'The project was delayed, which meant we had to revise the entire timeline.',hu:'A projekt késett, ami azt jelentette, hogy az egész ütemtervet át kellett dolgoznunk.'},{en:'This is the consultant with whom we\'ve been working for the past two years.',hu:'Ez az a tanácsadó, akivel az elmúlt két évben dolgoztunk.'}],
     warning:'"The client which we signed the contract" — HELYTELEN. Személyre: whom (formális): "the client with whom we signed".',
     contrast:'"The report that was submitted" = defining. "The report, which was submitted last week, has an error." = non-defining (vesszővel, plusz info).'},

    {id:'b2_word_formation', en:'Word Formation', title:'Word Formation', sub:'decision, implementation, cost-effective',
     use:'Szócsaládok ismerete bővíti a szókincset és segít a formális, szakmai stílus elsajátításában.',
     form:['Főnévképzők: -tion/-sion (decision), -ment (development), -ance/-ence (performance), -ity (productivity), -ness (effectiveness)','Melléknévképzők: -al (operational), -ive (competitive), -ful (successful), -less (effortless), -able (scalable)','Igeprefixek: out- (outperform), over- (overestimate), under- (underdeliver), re- (restructure)','Főnév+főnév összetételek: cost-cutting, decision-making, problem-solving'],
     signals:['Formális szövegben: főnevesítés (nominalization)','Üzleti szókincs: -tion, -ment végű főnevek'],
     examples:[{en:'The implementation of the new CRM system took longer than expected.',hu:'Az új CRM rendszer bevezetése tovább tartott a vártnál.'},{en:'We need to improve cost-effectiveness without sacrificing quality.',hu:'Javítanunk kell a költséghatékonyságon a minőség feláldozása nélkül.'},{en:'The team significantly outperformed its targets in Q4.',hu:'A csapat jelentősen felülmúlta a céljait Q4-ben.'}],
     warning:'"The decide was made by the board" — HELYTELEN. decide = ige, decision = főnév: "The decision was made..."',
     contrast:'Formális írásban előnyben részesítik a nominalizált alakokat: "the implementation of" (főnév) ahelyett hogy "when we implemented" (mellékmondatos).'},

    {id:'b2_phrasal_verbs', en:'Phrasal Verbs (Business)', title:'Business Phrasal Verbs', sub:'follow up, phase out, draw up, roll out',
     use:'Természetes, folyékony üzleti kommunikáció — különösen szóbeli helyzetekben és informálisabb üzleti e-mailekben.',
     form:['Elválasztható: draw up a plan / draw a plan up (de: draw it up)','El nem választható: deal with the issue (NEM: deal the issue with)','Formális szinonimák mindig léteznek: follow up = pursue, phase out = discontinue'],
     signals:['follow up (on): nyomon követni, visszatérni valamire','phase out: fokozatosan kivonni','roll out: bevezetni, elindítani','draw up: kidolgozni, összeállítani','bring forward: előrehozni','put off/postpone: elhalasztani'],
     examples:[{en:'I\'ll follow up with the client after the proposal.',hu:'Az ajánlat után felkeresem az ügyfelet.'},{en:'We\'re planning to phase out the legacy system by Q2.',hu:'A második negyedévre tervezzük az örökölt rendszer kivonását.'},{en:'The new onboarding process will be rolled out company-wide next month.',hu:'Az új onboarding folyamatot jövő hónapban vezetjük be vállalati szinten.'}],
     warning:'Üzleti e-mailben és formális szövegben inkább a latin gyökű igék: "pursue" (follow up), "discontinue" (phase out), "implement" (roll out).',
     contrast:'"Follow up" (általánosabb visszajelzés/nyomon követés) vs "follow through" (végigvinni valamit amit megkezdtél).'}
  ]},

  {level:'C1', title:'C1 — Folyékony', sub:'Natív szintű struktúrák', color:'cefr-c1', items:[

    {id:'c1_cleft', en:'Cleft Sentences', title:'Cleft Sentences', sub:'What we need is... / It was the pricing that...',
     use:'Egy mondatelem kiemelésére — fókuszálás, kontrasztálás, nyomatékosítás. Prezentációkban, tárgyalásokon hatásos.',
     form:['It-cleft: It was/is + kiemelendő elem + that/who + mellékmondat','Wh-cleft: What + mellékmondat + is/was + kiemelendő elem','All-cleft: All + mellékmondat + is/was + kiemelendő elem','Pseudo-cleft: The thing/reason/person that... is...'],
     signals:['Kiemelés, kontrasztálás: "It was the PRICE that..."','Prezentáció: "What we discovered was..."','Diplomatikus megfogalmazás: "What I\'m suggesting is..."'],
     examples:[{en:'It was the lack of communication, not the budget, that caused the project to fail.',hu:'A kommunikáció hiánya, nem a büdzsé okozta a projekt bukását.'},{en:'What we need is a clear escalation process.',hu:'Amire szükségünk van, az egy egyértelmű eszkalációs folyamat.'},{en:'All they asked for was a more transparent reporting system.',hu:'Mindössze átláthatóbb riportrendszert kértek.'}],
     warning:'"What we need it is..." — HELYTELEN. Wh-cleft: What + mellékmondat + is (nincs extra "it"): "What we need is..."',
     contrast:'It-cleft = a mondat végére helyezi a fókuszt. Wh-cleft = a végén emeli ki az új információt. All-cleft = minimalizálja, korlátozza a fókuszt.'},

    {id:'c1_inversion_advanced', en:'Advanced Inversion', title:'Advanced Inversion & Conditionals', sub:'Should you require... / Had we known...',
     use:'Formális, elegáns üzleti kommunikáció — levelek, szerződések, prezentációk nyitása/zárása.',
     form:['Inverted conditional (Should): Should + alany + V1 (= If + alany + should + V1)','Inverted conditional (Had): Had + alany + PP (= If + alany + had + PP)','Inverted conditional (Were): Were + alany + to + V1 (= If + alany + were to + V1)','Negatív határozók: Little did we know | Rarely do we see | Not since... has...'],
     signals:['Formális levelekben: "Should you require further assistance..."','Sajtóközleményben: "Were the merger to go ahead..."','Prezentációban: "Rarely have we seen such results."'],
     examples:[{en:'Should you require any further information, please do not hesitate to contact us.',hu:'Ha bármilyen további információra van szüksége, kérem ne habozzon felvenni velünk a kapcsolatot.'},{en:'Had we identified the risk earlier, we would have restructured the timeline.',hu:'Ha korábban azonosítottuk volna a kockázatot, átstrukturáltuk volna az ütemtervet.'},{en:'Were the company to merge, significant restructuring would be inevitable.',hu:'Ha a cég összeolvadna, jelentős átszervezés elkerülhetetlen lenne.'}],
     warning:'"Little I did know..." — HELYTELEN. Inverzió kötelező: "Little did I know..."',
     contrast:'Normál kondicionális = informálisabb. Inverted kondicionális = formálisabb, írásos szövegekbe való.'},

    {id:'c1_subjunctive', en:'Subjunctive', title:'The Subjunctive', sub:'I suggest that he be... / It is essential that...',
     use:'Formális javaslatok, követelmények, feltételek kifejezésére — jogi, üzleti, diplomáciai szövegekben.',
     form:['suggest/recommend/insist/demand/require/propose + that + alany + V1 ALAPALAK (nincs -s, nincs be)','It is essential/important/vital/necessary/imperative + that + alany + V1 alapalak','Past context: suggested that + alany + V1 (NEM "suggested that he reviewed")'],
     signals:['Formális dokumentumokban: "The committee recommends that..."','Szerződésekben: "The agreement requires that..."','Szakmai levelekben: "I suggest that the board consider..."'],
     examples:[{en:'The board recommends that all subsidiaries submit quarterly reports.',hu:'Az igazgatóság ajánlja, hogy az összes leányvállalat nyújtson be negyedéves jelentést.'},{en:'It is essential that every employee complete the compliance training.',hu:'Elengedhetetlen, hogy minden alkalmazott elvégezze a megfelelőségi képzést.'},{en:'I propose that the deadline be extended by two weeks.',hu:'Javasolom, hogy a határidőt két héttel hosszabbítsák meg.'}],
     warning:'"I recommend that he reviews the contract" — HELYTELEN. Subjunctive után V1 alapalak, nincs -s: "I recommend that he review the contract."',
     contrast:'Subjunctive vs Modal: "I suggest he review it" (subjunctive, formális) vs "I suggest he should review it" (modal, enyhén kevésbé formális — mindkettő elfogadott).'},

    {id:'c1_hedging', en:'Hedging Language', title:'Hedging & Softening', sub:'It would appear... / arguably... / tends to...',
     use:'Állítások enyhítése, bizonytalanság jelzése, diplomatikus fogalmazás — tudományos és üzleti kommunikációban alapvető.',
     form:['Igék: seem, appear, tend to, suggest, indicate, imply','Modálisok: might, could, may, would','Módosítók: somewhat, rather, quite, relatively, fairly, largely','Határozók: arguably, generally, broadly speaking, to some extent, in many cases','Tompítás: it would appear, it seems that, there is a tendency for'],
     signals:['Adatok óvatos interpretációjakor','Kritika udvarias megfogalmazásánál','Előrejelzéseknél és elemzéseknél'],
     examples:[{en:'It would appear that the current strategy is not delivering the expected results.',hu:'Úgy tűnik, a jelenlegi stratégia nem hozza a várt eredményeket.'},{en:'The data suggests a somewhat positive trend, though further analysis is needed.',hu:'Az adatok némileg pozitív tendenciát jeleznek, bár további elemzés szükséges.'},{en:'Arguably, this represents the most significant shift in our industry in a decade.',hu:'Vitathatatlanul ez jelenti az iparágunk legjelentősebb változását az elmúlt évtizedben.'}],
     warning:'"Arguably this is clearly the best solution" — HELYTELEN. Hedging és certainty ("clearly") egymást kizárják.',
     contrast:'Erős hedging: "It would appear..." | Gyenge hedging: "It seems..." | Minimális hedging: "Arguably..." | Nincs hedging: "This is the best solution." — Válassz a kontextushoz mérten.'},

    {id:'c1_discourse_markers', en:'Discourse Markers (C1)', title:'Advanced Discourse Markers', sub:'Nevertheless... / As a consequence... / That said...',
     use:'Összetett, koherens szövegek szerkesztéséhez — prezentációk, jelentések, elemzések strukturálásához.',
     form:['Összefoglalás: In conclusion, To summarise, All things considered, On balance','Kontrast/engedmény: Nevertheless, Notwithstanding, That said, Be that as it may','Ok-okozat: As a consequence, Hence, Thus, It follows that, Accordingly','Hangsúly: Above all, Most importantly, What is crucial is, It is worth noting','Kiegészítés: What is more, Over and above this, In addition to this'],
     signals:['Formális írott szöveg struktúrájában','Összekötő mondatok bekezdések között','Konklúziókban és összefoglalókban'],
     examples:[{en:'The Q3 results were disappointing; nevertheless, the board remains confident in the long-term strategy.',hu:'A Q3-as eredmények csalódást okoztak; mindazonáltal az igazgatóság bizakodó a hosszú távú stratégiát illetően.'},{en:'The merger was approved. As a consequence, all existing contracts will be renegotiated.',hu:'Az összeolvadást jóváhagyták. Ennek következtében az összes meglévő szerződést újratárgyalják.'},{en:'All things considered, this represents the best available option.',hu:'Mindent egybevetve, ez jelenti a legjobb elérhető lehetőséget.'}],
     warning:'"Despite, we continued" — HELYTELEN. "Despite" prepozíció, mondatkezdőként NEM használható. Használj "Nevertheless" vagy "However" helyette.',
     contrast:'"However" (általánosabb, semlegesebb) vs "Nevertheless" (erősebb kontrast, tartja az álláspontot) vs "That said" (engedményes, de...) — mind kontrast, de különböző erősséggel.'},

    {id:'c1_nominalisation', en:'Nominalisation', title:'Nominalisation', sub:'the implementation of... / decision-making...',
     use:'Igékből és melléknevekből főnevet képzünk — formálisabb, tömörebb, objektívebb stílust eredményez. Üzleti és tudományos szövegek jellemzője.',
     form:['Ige → főnév: implement→implementation, decide→decision, achieve→achievement, develop→development','Melléknév → főnév: effective→effectiveness, significant→significance, stable→stability','Összetett főnevek: cost-cutting, decision-making, problem-solving, capacity-building','Nominalizált szerkezet: "the + főnév + of": "the implementation of the strategy"'],
     signals:['Formális szöveg (riport, elemzés, javaslat)','Tárgyias, személytelen hang','Az ige helyett annak főnévi változata'],
     examples:[{en:'The successful implementation of the new strategy led to a 30% increase in efficiency.',hu:'Az új stratégia sikeres végrehajtása 30%-os hatékonyságnövekedéshez vezetett.'},{en:'Effective decision-making at board level requires transparent reporting.',hu:'Az igazgatósági szintű hatékony döntéshozatal átlátható riportingot igényel.'},{en:'There has been a significant improvement in team performance since the restructuring.',hu:'A csapat teljesítményében jelentős javulás mutatkozott az átszervezés óta.'}],
     warning:'"The improve of performance was notable" — HELYTELEN. improve = ige, improvement = főnév: "The improvement in performance was notable."',
     contrast:'Igés változat (informális): "When we implemented the strategy, efficiency increased." Nominalizált (formális): "The implementation of the strategy led to an increase in efficiency."'},

    {id:'c1_emphasis_fronting', en:'Emphasis & Fronting', title:'Emphasis & Fronting', sub:'What I find remarkable... / This we cannot ignore.',
     use:'Mondatelemek előrehozása nyomaték, kontraszt és retorikai hatás céljából — prezentációkban és formális szövegekben.',
     form:['Wh-kiemelés: What strikes me is... / What matters here is... / What we need is...','Fronting (tárgy előre): "This proposal I find particularly promising."','Emphatic do/did/does: "I do believe this is the right approach."','Adjective fronting: "Particularly impressive is the growth in emerging markets."'],
     signals:['Prezentáció csúcspontjainál','Várakozás keltésekor: "What I\'d like to propose is..."','Erős meggyőzésnél: "I do believe..."'],
     examples:[{en:'What I find most impressive is the team\'s commitment to quality under pressure.',hu:'Ami a leglenyűgözőbb számomra, az a csapat minőség iránti elkötelezettsége nyomás alatt.'},{en:'I do believe this partnership represents a genuine opportunity for growth.',hu:'Valóban hiszem, hogy ez a partnerség valódi növekedési lehetőséget jelent.'},{en:'Particularly striking is the contrast between Q1 and Q3 performance.',hu:'Különösen szembeötlő a Q1-es és Q3-as teljesítmény közötti kontraszt.'}],
     warning:'"What I find it most impressive is..." — HELYTELEN. Wh-cleft: What + mellékmondat + is (nincs extra "it").',
     contrast:'Normál szórend = tény közlés. Fronting/kiemelés = hangsúly, retorikai hatás, meggyőzés.'},

    {id:'c1_register', en:'Register & Style', title:'Register & Formal Style', sub:'formal, semi-formal, diplomatic language',
     use:'C1 szinten a tudatos regiszterváltás — mikor formális, mikor informális, hogyan fogalmazz diplomatikusan üzleti helyzetekben.',
     form:['Formális: Latin gyökű igék (commence, terminate, facilitate, endeavour, ascertain)','Informális: Germán/angol tőből eredő szavak (start, end, help, try, find out)','Diplomatikus: softeners (I\'m afraid, Unfortunately, With respect, I would suggest)','Eufemizmus: let go (kirúg), downsize (elbocsátás), challenging (nehéz), going forward (ezentúl)','Tompítás: "It may be worth considering..." vs "You should..."'],
     signals:['Formális: jogi, szerződéses, igazgatósági szövegek','Semi-formális: üzleti e-mail, jelentés','Diplomatikus: rossz hírek közlése, kritika, visszautasítás'],
     examples:[{en:'I regret to inform you that we are unable to proceed with the current proposal.',hu:'Sajnálattal tájékoztatom, hogy a jelenlegi javaslattal nem tudunk továbblépni.'},{en:'It may be worth considering an alternative approach to the pricing model.',hu:'Érdemes lenne megfontolni a díjszabási modell alternatív megközelítését.'},{en:'We will be letting ten members of staff go as part of the restructuring.',hu:'Az átszervezés keretében tíz munkatárstól válunk meg.'}],
     warning:'"We are firing 20 employees" — Formális/HR kontextusban kerülendő. Eufemizmus: "we are letting staff go" / "we are making redundancies" / "restructuring the team".',
     contrast:'Formális szó vs informális: commence/start | terminate/end | endeavour/try | ascertain/find out | remuneration/pay | prior to/before — mindkettő helyes, de más kontextusban.'}
  ]}
];


